#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int A, B;
        scanf("%d %d", &A, &B);
        if (A == B) {
            printf("Draw\n");
        } else if (A > B) {
            printf("Chef\n");
        } else {
            printf("Chefina\n");
        }
    }
    return 0;
}

